import type { FeatureCollection, Geometry, GeometryCollection } from '@turf/helpers';
export interface ISourceOptions {
    dataInfo?: string;
    version: string;
    type?: 'wgs84' | 'gcj02';
    getCdnUrl?: (params: any) => string;
}
export type DataPrecision = 'high' | 'middle' | 'low';
export interface IDataOptions {
    precision: DataPrecision;
    level: DataLevel;
    code: number;
}
export interface ChildrenDataOptions {
    parentAdcode: number;
    parentLevel: DataLevel;
    childrenLevel: DataLevel;
    precision: DataPrecision;
}
export type DataLevel = 'country' | 'province' | 'city' | 'county' | 'jiuduanxian';
export interface ISourceInfo {
    url: string;
    desc: {
        text: string;
        href: string;
    };
}
export default abstract class BaseSource {
    info: Partial<ISourceInfo>;
    protected options: Partial<ISourceOptions>;
    protected data: {
        [K in DataLevel]: FeatureCollection | undefined;
    };
    protected version: string;
    protected type: 'wgs84' | 'gcj02';
    constructor(options: Partial<ISourceOptions>);
    protected abstract getDefaultOptions(): Partial<ISourceOptions>;
    abstract getRenderData(options: Partial<IDataOptions>): Promise<FeatureCollection<Geometry | GeometryCollection, Record<string, any>>>;
    abstract getData(options: Partial<IDataOptions>): Promise<FeatureCollection<Geometry | GeometryCollection, Record<string, any>>>;
    abstract getChildrenData(ChildrenDataOptions: Partial<ChildrenDataOptions>): Promise<FeatureCollection<Geometry | GeometryCollection, Record<string, any>>>;
    protected fetchJsonData: (url: string) => Promise<any>;
}
